-- ----------------------------
-- Table structure for body_metric_record
-- ----------------------------
DROP TABLE IF EXISTS `body_metric_record`;
CREATE TABLE `body_metric_record`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `record_date` date NOT NULL COMMENT '记录日期（建议每周/每月选一天）',
  `weight_kg` decimal(5, 2) NULL DEFAULT NULL COMMENT '体重(kg)',
  `body_fat_pct` decimal(5, 2) NULL DEFAULT NULL COMMENT '体脂率(%)',
  `chest_cm` decimal(5, 2) NULL DEFAULT NULL COMMENT '胸围(cm)',
  `waist_cm` decimal(5, 2) NULL DEFAULT NULL COMMENT '腰围(cm)',
  `hip_cm` decimal(5, 2) NULL DEFAULT NULL COMMENT '臀围(cm)',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_date`(`user_id` ASC, `record_date` ASC) USING BTREE,
  INDEX `idx_user_date`(`user_id` ASC, `record_date` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 52 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '身体指标记录表' ROW_FORMAT = Dynamic;

