-- Table structure for diet_record
-- ----------------------------
DROP TABLE IF EXISTS `diet_record`;
CREATE TABLE `diet_record`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `food_item_id` bigint NOT NULL COMMENT '食物ID',
  `meal_type` tinyint NOT NULL COMMENT '餐次：1早餐 2午餐 3晚餐 4加餐',
  `intake_gram` decimal(8, 2) NOT NULL COMMENT '摄入重量(g)',
  `calorie_per_100g` decimal(8, 2) NOT NULL COMMENT '记录时食物每100g热量快照',
  `total_calories` decimal(8, 2) NOT NULL COMMENT '本次摄入总热量(kcal)',
  `record_date` date NOT NULL COMMENT '记录日期',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_date`(`user_id` ASC, `record_date` ASC) USING BTREE,
  INDEX `idx_user_meal_date`(`user_id` ASC, `meal_type` ASC, `record_date` ASC) USING BTREE,
  INDEX `idx_food_item_id`(`food_item_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 142 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '饮食记录表' ROW_FORMAT = Dynamic;

