-- ----------------------------
-- Table structure for food_item
-- ----------------------------
DROP TABLE IF EXISTS `food_item`;
CREATE TABLE `food_item`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` bigint NULL DEFAULT NULL COMMENT '所属用户ID；NULL表示系统内置',
  `food_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '食物名称',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '分类：主食/肉类/水果/饮品等',
  `calorie_per_100g` decimal(8, 2) NOT NULL COMMENT '每100g热量(kcal)',
  `protein_per_100g` decimal(8, 2) NULL DEFAULT NULL COMMENT '每100g蛋白质(g)',
  `fat_per_100g` decimal(8, 2) NULL DEFAULT NULL COMMENT '每100g脂肪(g)',
  `carb_per_100g` decimal(8, 2) NULL DEFAULT NULL COMMENT '每100g碳水(g)',
  `unit_hint` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'g' COMMENT '默认单位提示',
  `is_builtin` tinyint NOT NULL DEFAULT 1 COMMENT '是否内置：1是 0否',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态：1启用 0停用',
  `deleted` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除：0否 1是',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_food_name`(`food_name` ASC) USING BTREE,
  INDEX `idx_category`(`category` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 30 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '食物库表' ROW_FORMAT = Dynamic;

