  `sport_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '运动类型',
  `duration_min` int NOT NULL COMMENT '运动时长(分钟)',
  `distance_km` decimal(6, 2) NULL DEFAULT NULL COMMENT '距离(km)',
