-- ----------------------------
-- Table structure for user_sport_plan
-- ----------------------------
DROP TABLE IF EXISTS `user_sport_plan`;
CREATE TABLE `user_sport_plan`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `week_start_date` date NOT NULL COMMENT '周开始日期（周一）',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '计划名称',
  `source_type` tinyint NOT NULL DEFAULT 2 COMMENT '来源：1模板生成 2自定义',
  `template_id` bigint NULL DEFAULT NULL COMMENT '来源模板ID（可空）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_week`(`user_id` ASC, `week_start_date` ASC) USING BTREE,
  INDEX `idx_user_week`(`user_id` ASC, `week_start_date` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 16 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户周运动计划' ROW_FORMAT = Dynamic;

