-- ----------------------------
-- Table structure for user_sport_plan_item
-- ----------------------------
DROP TABLE IF EXISTS `user_sport_plan_item`;
CREATE TABLE `user_sport_plan_item`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `plan_id` bigint NOT NULL COMMENT '周计划ID',
  `user_id` bigint NOT NULL COMMENT '用户ID（冗余，便于统计）',
  `plan_date` date NOT NULL COMMENT '计划日期（由week_start_date + day_of_week换算）',
  `day_of_week` tinyint NOT NULL COMMENT '周几：1-7（1=周一）',
  `sport_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '运动类型',
  `target_duration_min` int NOT NULL COMMENT '目标时长(分钟)',
  `target_distance_km` decimal(6, 2) NULL DEFAULT NULL COMMENT '目标距离(km)',
  `remind_time` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '提醒时间(HH:mm)',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `done` tinyint NOT NULL DEFAULT 0 COMMENT '是否完成：0否 1是',
  `done_time` datetime NULL DEFAULT NULL COMMENT '完成时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_date`(`user_id` ASC, `plan_date` ASC) USING BTREE,
  INDEX `idx_plan`(`plan_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 75 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户周计划明细' ROW_FORMAT = Dynamic;

